import axios from 'axios';

const API_URL =
'http://localhost:8080/api/resume';

class ResumeService {

  getAllResumes() {

    return axios.get(API_URL);
  }

  saveResume(resume) {

    return axios.post(
      API_URL,
      resume
    );
  }

  getResumeById(id) {

    return axios.get(
      API_URL + '/' + id
    );
  }

  deleteResume(id) {

    return axios.delete(
      API_URL + '/' + id
    );
  }

  // AI SUMMARY API

  generateSummary(skills) {

    return axios.post(

      API_URL + '/generate-summary',

      skills,

      {

        headers: {

          'Content-Type':
          'text/plain'

        }

      }
    );
  }
}

export default new ResumeService();
